import java.util.Scanner;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Ensuring that the buffer size matches the input length
        char[] buffer = new char[name.length()];

        // Copying the user input (name) into the buffer with proper bounds checking
        for (int i = 0; i < name.length(); i++) {
            if (i < buffer.length) {
                buffer[i] = name.charAt(i);
            } else {
                break; // Stop copying if buffer is full
            }
        }

        System.out.println("Welcome, " + new String(buffer));
    }
}

